     5|  --bg-card: #222;
     6|  --bg-hover: #2a2a2a;
     7|  --text-primary: #e0e0e0;
     8|  --text-secondary: #aaa;
     9|  --text-muted: #777;
    10|  --accent: #9C27B0;
    11|  --accent-hover: #ba68c8;
    12|  --accent-dim: rgba(156, 39, 176, 0.15);
    13|  --border: #333;
    14|  --radius: 12px;
    15|  --radius-sm: 8px;
    16|  --shadow: 0 4px 20px rgba(0,0,0,0.4);
    17|  --font: system-ui, -apple-system, 'Segoe UI', Roboto, Helvetica, Arial, sans-serif;
    18|  --max-width: 1100px;
    19|}
    20|*, *::before, *::after { box-sizing: border-box; margin: 0; padding: 0; }
    21|html { scroll-behavior: smooth; }
    22|body {
    23|  font-family: var(--font);
    24|  background: var(--bg-primary);
    25|  color: var(--text-primary);
    26|  line-height: 1.7;
    27|  min-height: 100vh;
    28|  display: flex;
    29|  flex-direction: column;
    30|}
    31|a { color: var(--accent); text-decoration: none; transition: color .2s; }
    32|a:hover { color: var(--accent-hover); }
    33|img { max-width: 100%; height: auto; display: block; }
    34|
    35|/* Container */
    36|.container { max-width: var(--max-width); margin: 0 auto; padding: 0 20px; }
    37|
    38|/* ===== Navigation ===== */
