   109|  display: inline-block;
   110|  padding: 8px 18px;
   111|  border-radius: 20px;
   112|  background: var(--accent-dim);
   113|  color: var(--accent-hover);
   114|  font-size: 0.85rem;
   115|  font-weight: 600;
   116|  border: 1px solid rgba(156,39,176,0.3);
   117|}
   118|
   119|/* ===== Category Filter ===== */
   120|.cat-filter {
   121|  padding: 30px 0 10px;
   122|  display: flex;
   123|  justify-content: center;
   124|  gap: 10px;
   125|  flex-wrap: wrap;
   126|}
   127|.cat-filter a {
   128|  padding: 8px 20px;
   129|  border-radius: 20px;
   130|  background: var(--bg-card);
   131|  color: var(--text-secondary);
   132|  font-size: 0.9rem;
   133|  font-weight: 500;
   134|  border: 1px solid var(--border);
   135|  transition: all .2s;
   136|}
   137|.cat-filter a:hover,
   138|.cat-filter a.active {
   139|  background: var(--accent-dim);
   140|  color: var(--accent-hover);
   141|  border-color: var(--accent);
   142|}
   143|
   144|/* ===== Blog Grid ===== */
   145|.blog-grid {
   146|  display: grid;
   147|  grid-template-columns: repeat(auto-fill, minmax(320px, 1fr));
   148|  gap: 24px;
   149|  padding: 30px 0 60px;
