   166|  height: 200px;
   167|  background: linear-gradient(135deg, #1a1a2e, #2d1b3d);
   168|  display: flex;
   169|  align-items: center;
   170|  justify-content: center;
   171|  color: var(--text-muted);
   172|  font-size: 0.9rem;
   173|  border-bottom: 1px solid var(--border);
   174|  position: relative;
   175|  overflow: hidden;
