   177|.blog-card .card-img img {
   178|  width: 100%;
   179|  height: 100%;
   180|  object-fit: cover;
   181|  display: block;
   182|}
   183|
   184|.blog-card .card-img .placeholder-icon {
   185|  font-size: 3rem;
