   260|  margin-bottom: 20px;
   261|}
   262|.article-page .article-content {
   263|  font-size: 1.05rem;
   264|  color: var(--text-primary);
   265|  max-width: 750px;
   266|}
   267|.article-page .article-content p {
   268|  margin-bottom: 20px;
   269|}
   270|.article-page .article-content h2 {
   271|  font-size: 1.6rem;
   272|  margin: 36px 0 16px;
   273|  color: var(--text-primary);
   274|}
   275|.article-page .article-content h3 {
   276|  font-size: 1.25rem;
   277|  margin: 28px 0 12px;
   278|  color: var(--text-primary);
   279|}
   280|.article-page .article-content ul,
   281|.article-page .article-content ol {
   282|  margin: 0 0 20px 20px;
   283|}
   284|.article-page .article-content li {
   285|  margin-bottom: 8px;
   286|}
   287|.article-page .article-content .highlight-box {
   288|  background: var(--accent-dim);
   289|  border-left: 4px solid var(--accent);
   290|  padding: 16px 20px;
   291|  border-radius: 0 var(--radius-sm) var(--radius-sm) 0;
   292|  margin: 24px 0;
   293|}
   294|.article-page .article-content .highlight-box p:last-child { margin-bottom: 0; }
   295|
