   302|  margin: 30px 0;
   303|  text-align: center;
   304|}
   305|.affiliate-box p {
   306|  color: var(--text-muted);
   307|  font-size: 0.85rem;
   308|  margin-bottom: 12px !important;
   309|}
   310|.affiliate-box .btn {
   311|  display: inline-block;
   312|  padding: 12px 28px;
   313|  background: var(--accent);
   314|  color: #fff;
   315|  border-radius: var(--radius-sm);
   316|  font-weight: 600;
   317|  transition: background .2s;
   318|}
   319|.affiliate-box .btn:hover { background: var(--accent-hover); color: #fff; }
   320|.adsense-placeholder {
