   322|  border: 2px dashed var(--border);
   323|  border-radius: var(--radius);
   324|  padding: 40px 20px;
   325|  text-align: center;
   326|  color: var(--text-muted);
   327|  font-size: 0.85rem;
   328|  margin: 30px 0;
   329|}
   330|.adsense-placeholder strong { color: var(--text-secondary); }
