   338|  margin-bottom: 24px;
   339|}
   340|.static-page h2 {
   341|  font-size: 1.4rem;
   342|  margin: 30px 0 14px;
   343|  color: var(--text-primary);
   344|}
   345|.static-page p {
   346|  margin-bottom: 16px;
   347|  color: var(--text-secondary);
   348|  max-width: 700px;
   349|}
   350|.static-page .legal-block {
   351|  background: var(--bg-card);
   352|  border: 1px solid var(--border);
   353|  border-radius: var(--radius);
   354|  padding: 24px;
   355|  margin-bottom: 16px;
   356|}
   357|.static-page .legal-block h3 {
   358|  color: var(--accent);
   359|  margin-bottom: 8px;
   360|  font-size: 1rem;
   361|}
   362|
   363|/* ===== Footer ===== */
   364|.footer {
   365|  background: var(--bg-secondary);
   366|  border-top: 1px solid var(--border);
   367|  padding: 40px 0 24px;
   368|  margin-top: auto;
   369|}
   370|.footer .footer-grid {
   371|  display: grid;
   372|  grid-template-columns: repeat(auto-fit, minmax(200px, 1fr));
   373|  gap: 30px;
   374|  margin-bottom: 20px;
   375|}
   376|.footer h4 {
   377|  font-size: 1rem;
   378|  color: var(--text-primary);
   379|  margin-bottom: 12px;
   380|}
   381|.footer ul { list-style: none; }
   382|.footer ul li { margin-bottom: 6px; }
   383|.footer ul a { color: var(--text-muted); font-size: 0.9rem; }
   384|.footer ul a:hover { color: var(--accent); }
   385|.footer .footer-bottom {
   386|  border-top: 1px solid var(--border);
   387|  padding-top: 20px;
   388|  display: flex;
   389|  justify-content: space-between;
   390|  flex-wrap: wrap;
   391|  gap: 10px;
   392|  font-size: 0.85rem;
   393|  color: var(--text-muted);
   394|}
   395|.footer .affiliate-note {
   396|  font-size: 0.75rem;
   397|  color: var(--text-muted);
   398|  margin-top: 6px;
   399|}
